node --input-type=module -e "
function parseTimeForDate(timeStr, baseDate) {
  const [hours, minutes] = timeStr.split(':').map(Number);
  const result = new Date(baseDate);
  result.setHours(hours, minutes, 0, 0);
  return result;
}

function getYesterday(date) {
  const result = new Date(date);
  result.setDate(result.getDate() - 1);
  return result;
}

const now = new Date('2026-01-15T07:01:00Z');
const lastEvalTime = new Date('2026-01-15T06:59:00Z');

const todayCandidate = parseTimeForDate('07:00', now);
const yesterday = getYesterday(now);
const yesterdayCandidate = parseTimeForDate('07:00', yesterday);

console.log('now:', now.toISOString(), '- local:', now.toString());
console.log('lastEvalTime:', lastEvalTime.toISOString(), '- local:', lastEvalTime.toString());
console.log('todayCandidate:', todayCandidate.toISOString(), '- local:', todayCandidate.toString());
console.log('yesterday:', yesterday.toISOString());
console.log('yesterdayCandidate:', yesterdayCandidate.toISOString());
console.log('');
console.log('todayCandidate > lastEvalTime?', todayCandidate > lastEvalTime);
console.log('todayCandidate <= now?', todayCandidate <= now);
"

