      weekend: { conditions: [{ type: 'time', at: '00:00' }] },
      states: { test: { onoff: false } }
    },
    EVENING: {
      weekday: { conditions: [{ type: 'time', at: '00:00' }] },
      weekend: { conditions: [{ type: 'time', at: '00:00' }] },
      states: { test: { onoff: true } }
    }
  }
};

// Need lastEvalTime such that 00:00 yesterday is in the window but 00:00 today is after window
// Window is (lastEvalTime, now] with 24h clamp
// If now = 15T12:00 and lastEvalTime = 14T01:00, window = 14T01:00 to 15T12:00
// Yesterday 00:00 = 14T00:00 which is BEFORE windowStart → not included
// Wait, that's not right.

// Actually need: lastEvalTime < 00:00 today < now, and 00:00 yesterday < (now - 24h)
// If now = 15T12:00 and lastEvalTime = 14T23:00, window = (14T23:00, 15T12:00]
// 00:00 today = 15T00:00 is in window! 

const now = new Date('2026-01-15T12:00:00Z');
const lastEvalTime = new Date('2026-01-14T23:00:00Z'); // 13h ago

const ctx = {
  now,
  lux: null,
  latitude: 52.37,
  longitude: 4.90,
  countryCode: ''
};

console.log('now:', now.toISOString());
console.log('lastEvalTime:', lastEvalTime.toISOString());

const result = evaluatePhase('NIGHT', lastEvalTime, degenerateConfig, ctx);
console.log('result.phase:', result.phase);
console.log('result.transitions.length:', result.transitions.length);
console.log('result.cappedAt:', result.cappedAt);
"

